1	/**
2	 * Unit tests for src/server/worktree/branch.ts
3	 *
4	 * Covers:
5	 *   AC-1  Branch name matches yoke/<slug>-<shortid> pattern.
6	 *   RC-4  No path traversal possible through branch naming (slug contains
7	 *         only [a-z0-9-] — '/' and '..' are impossible in the slug).
8	 *
9	 * All tests are pure — no I/O, no filesystem, no child processes.
10	 */
11	
12	import { describe, it, expect } from 'vitest';
13	import {
14	  slugify,
15	  makeShortId,
16	  makeBranchName,
17	  makeWorktreeDirName,
18	} from '../../src/server/worktree/branch.js';
19	
20	// ---------------------------------------------------------------------------
21	// slugify()
22	// ---------------------------------------------------------------------------
23	
24	describe('slugify()', () => {
25	  it('lowercases ASCII', () => {
26	    expect(slugify('AddAuth')).toBe('addauth');
27	  });
28	
29	  it('converts spaces to hyphens', () => {
30	    expect(slugify('add auth')).toBe('add-auth');
31	  });
32	
33	  it('collapses multiple non-alphanumeric chars to a single hyphen', () => {
34	    expect(slugify('add  auth!!!')).toBe('add-auth');
35	  });
36	
37	  it('strips leading hyphens', () => {
38	    expect(slugify('!add-auth')).toBe('add-auth');
39	  });
40	
41	  it('strips trailing hyphens', () => {
42	    expect(slugify('add-auth!')).toBe('add-auth');
43	  });
44	
45	  it('handles a clean name unchanged', () => {
46	    expect(slugify('add-auth')).toBe('add-auth');
47	  });
48	
49	  it('handles numbers', () => {
50	    expect(slugify('feature-42')).toBe('feature-42');
51	  });
52	
53	  it('falls back to "workflow" for an empty input', () => {
54	    expect(slugify('')).toBe('workflow');
55	  });
56	
57	  it('falls back to "workflow" for an all-symbol input', () => {
58	    expect(slugify('!!! ???')).toBe('workflow');
59	  });
60	
61	  it('truncates slugs that exceed MAX_SLUG_LENGTH (40 chars)', () => {
62	    const longName = 'a'.repeat(80);
63	    const result = slugify(longName);
64	    expect(result.length).toBeLessThanOrEqual(40);
65	    expect(result).toBe('a'.repeat(40));
66	  });
67	
68	  it('produces only [a-z0-9-] characters — no slash or dot traversal possible', () => {
69	    const suspicious = '../../etc/passwd';
70	    const slug = slugify(suspicious);
71	    // Every character is either a-z, 0-9, or '-'
72	    expect(slug).toMatch(/^[a-z0-9-]+$/);
73	    // No path traversal characters
74	    expect(slug).not.toContain('/');
75	    expect(slug).not.toContain('.');
