59	/** Creates a git repository in dir with a single initial commit. */
60	function gitInit(dir: string): void {
61	  fs.mkdirSync(dir, { recursive: true });
62	  execFileSync('git', ['init', '--initial-branch=main', dir]);
63	  execFileSync('git', ['-C', dir, 'config', 'user.email', 'test@yoke.dev']);
64	  execFileSync('git', ['-C', dir, 'config', 'user.name', 'Yoke Test']);
65	  // Create an initial commit so git worktree add works (requires a commit).
66	  const readme = path.join(dir, 'README.md');
67	  fs.writeFileSync(readme, '# yoke test repo\n');
68	  execFileSync('git', ['-C', dir, 'add', 'README.md']);
69	  execFileSync('git', ['-C', dir, 'commit', '-m', 'initial commit']);
70	}
71	
72	/** Creates a bare repository (used as a fake remote). */
73	function gitInitBare(dir: string): void {
74	  fs.mkdirSync(dir, { recursive: true });
75	  execFileSync('git', ['init', '--bare', dir]);
76	}
77	
78	/** Adds a remote named 'origin' pointing to remotePath. */
79	function gitAddRemote(repoDir: string, remotePath: string): void {
80	  execFileSync('git', ['-C', repoDir, 'remote', 'add', 'origin', remotePath]);
81	}
82	
83	/** Pushes the given branch to origin. */
84	function gitPush(repoDir: string, branch: string): void {
85	  execFileSync('git', ['-C', repoDir, 'push', 'origin', branch]);
86	}
