88	/** Makes a commit on the given worktree. */
89	function gitCommitInWorktree(worktreePath: string, message: string): void {
90	  const file = path.join(worktreePath, 'change.txt');
91	  fs.writeFileSync(file, `${message}\n`);
92	  execFileSync('git', ['-C', worktreePath, 'add', 'change.txt']);
93	  execFileSync('git', ['-C', worktreePath, 'commit', '-m', message]);
94	}
